const springConfig = {
  stiffness: 220,
  damping: 28,
  mass: 0.7,
}

function seededRandom(index: number, offset = 0) {
  const value = Math.sin((index + 1) * 999 + offset) * 10000
  return value - Math.floor(value)
}

function randomBetween(index: number, min: number, max: number, offset = 0) {
  return min + seededRandom(index, offset) * (max - min)
}

export default function LogoCloudFour() {
  return (
    <section className="bg-background py-20">
      <div className="mx-auto w-full max-w-6xl px-6">
        <div className="mx-auto mb-12 max-w-2xl text-center">
          <h2 className="text-3xl font-semibold tracking-tight text-balance text-zinc-950 sm:text-4xl dark:text-white">
            Built with the tools teams already trust
          </h2>

          <p className="mt-3 text-sm leading-6 text-balance text-zinc-600 sm:text-base dark:text-zinc-400">
            From design and code to auth, deployment, and AI, these are the platforms behind
            fast-moving product teams.
          </p>
        </div>

        <div className="relative isolate">
          <div role="list" className="relative z-10 grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4">
            {companies.map((company, index) => (
              <LogoCell key={company.name} company={company} index={index} />
            ))}
          </div>
        </div>
      </div>
    </section>
  )
}

function LogoCell({ company, index }: { company: Company; index: number }) {
  const cellRef = useRef<HTMLDivElement>(null)

  const mouseX = useMotionValue(0)
  const mouseY = useMotionValue(0)
  const glowOpacity = useMotionValue(0)

  const smoothX = useSpring(mouseX, springConfig)
  const smoothY = useSpring(mouseY, springConfig)
  const smoothOpacity = useSpring(glowOpacity, springConfig)

  const blinkDuration = randomBetween(index, 5.5, 10, 1)
  const blinkDelay = randomBetween(index, 0, 3.8, 2)

  const softCardGlow = useMotionTemplate`
  radial-gradient(
    220px circle at ${smoothX}px ${smoothY}px,
    rgb(var(--glow-card) / 0.10),
    rgb(var(--glow-card) / 0.04) 34%,
    transparent 70%
  )
`

  const borderGlow = useMotionTemplate`
  radial-gradient(
    180px circle at ${smoothX}px ${smoothY}px,
    rgb(var(--glow-border) / 0.9),
    rgb(var(--glow-border) / 0.45) 38%,
    transparent 72%
  )
`
  function handlePointerMove(event: React.PointerEvent<HTMLDivElement>) {
    const rect = cellRef.current?.getBoundingClientRect()

    if (!rect) return

    mouseX.set(event.clientX - rect.left)
    mouseY.set(event.clientY - rect.top)
  }

  function handlePointerEnter(event: React.PointerEvent<HTMLDivElement>) {
    handlePointerMove(event)
    glowOpacity.set(1)
  }

  function handlePointerLeave() {
    glowOpacity.set(0)
  }

  return (
    <div
      ref={cellRef}
      role="listitem"
      aria-label={company.name}
      onPointerMove={handlePointerMove}
      onPointerEnter={handlePointerEnter}
      onPointerLeave={handlePointerLeave}
      className="group/cell relative flex min-h-32 items-center justify-center overflow-visible px-8 py-10 [--glow-border:190_242_100] [--glow-card:163_230_53]"
    >
      {/* soft background glow */}
      <motion.div
        aria-hidden="true"
        className="pointer-events-none absolute inset-px z-0"
        style={{
          background: softCardGlow,
          opacity: smoothOpacity,
        }}
      />

      <FadedCellLines />

      {/* stronger cursor border glow */}
      <motion.div
        aria-hidden="true"
        className="pointer-events-none absolute inset-0 z-20 rounded-none p-px"
        style={{
          background: borderGlow,
          opacity: smoothOpacity,
          WebkitMask: 'linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0)',
          WebkitMaskComposite: 'xor',
          maskComposite: 'exclude',
        }}
      />

      <CornerDots index={index} />

      <motion.div
        className={cn(
          'relative z-10 flex items-center justify-center text-zinc-950/90 transition-transform duration-300 group-hover/cell:scale-103 dark:text-white/90',
          '[&_svg]:h-8 [&_svg]:w-auto [&_svg]:max-w-32',
          '[&_svg_*]:fill-current',
        )}
        animate={{
          opacity: [1, 1, 0.35, 1, 0.55, 1, 1],
          filter: [
            'grayscale(1) brightness(0.9)',
            'grayscale(1) brightness(0.9)',
            'grayscale(1) brightness(1.45)',
            'grayscale(1) brightness(0.85)',
            'grayscale(1) brightness(1.25)',
            'grayscale(1) brightness(0.95)',
            'grayscale(1) brightness(0.9)',
          ],
        }}
        transition={{
          duration: blinkDuration,
          delay: blinkDelay,
          repeat: Number.POSITIVE_INFINITY,
          ease: 'easeInOut',
          times: [0, 0.7, 0.73, 0.76, 0.8, 0.84, 1],
        }}
      >
        {company.icon}
      </motion.div>
    </div>
  )
}
function FadedCellLines() {
  return (
    <div aria-hidden="true" className="pointer-events-none absolute inset-0 z-10">
      <span className="absolute top-0 left-0 h-px w-full bg-linear-to-r from-transparent via-zinc-300/75 to-transparent transition duration-300 group-hover/cell:via-lime-300/95 group-hover/cell:shadow-[0_0_18px_rgb(190_242_100/0.85)] dark:via-white/15" />
      <span className="absolute bottom-0 left-0 h-px w-full bg-linear-to-r from-transparent via-zinc-300/75 to-transparent transition duration-300 group-hover/cell:via-lime-300/95 group-hover/cell:shadow-[0_0_18px_rgb(190_242_100/0.85)] dark:via-white/15" />
      <span className="absolute top-0 left-0 h-full w-px bg-linear-to-b from-transparent via-zinc-300/75 to-transparent transition duration-300 group-hover/cell:via-lime-300/95 group-hover/cell:shadow-[0_0_18px_rgb(190_242_100/0.85)] dark:via-white/15" />
      <span className="absolute top-0 right-0 h-full w-px bg-linear-to-b from-transparent via-zinc-300/75 to-transparent transition duration-300 group-hover/cell:via-lime-300/95 group-hover/cell:shadow-[0_0_18px_rgb(190_242_100/0.85)] dark:via-white/15" />
    </div>
  )
}

function CornerDots({ index }: { index: number }) {
  const duration = randomBetween(index, 2.5, 4.8, 3)
  const delay = randomBetween(index, 0, 2.2, 4)

  const dots = ['left-0 top-0', 'right-0 top-0', 'bottom-0 left-0', 'bottom-0 right-0']

  return (
    <>
      {dots.map((position, dotIndex) => (
        <motion.span
          key={position}
          aria-hidden="true"
          className={cn(
            'pointer-events-none absolute z-30 size-1 rounded-full bg-zinc-400/70 transition duration-300 group-hover/cell:bg-lime-300 group-hover/cell:shadow-[0_0_14px_rgb(190_242_100/0.95)] dark:bg-white/35',
            position.includes('left') && '-translate-x-1/2',
            position.includes('right') && 'translate-x-1/2',
            position.includes('top') && '-translate-y-1/2',
            position.includes('bottom') && 'translate-y-1/2',
            position,
          )}
          animate={{
            opacity: [0.15, 0.95, 0.25, 0.7, 0.15],
            scale: [1, 1.2, 0.9, 1.08, 1],
          }}
          transition={{
            duration,
            delay: delay + dotIndex * 0.2,
            repeat: Number.POSITIVE_INFINITY,
            ease: 'easeInOut',
          }}
        />
      ))}
    </>
  )
}
